mapper.select:
SELECT id, name, category, original_filename AS originalFilename, file_size AS fileSize, content_type AS contentType, created_at AS uploadedAt, vector_status AS vectorStatus, vector_error AS vectorError, chunk_count AS chunkCount FROM knowledge_base WHERE del_flag = 0
AND ( name LIKE CONCAT('%', #{dto.keyword}, '%') OR original_filename LIKE CONCAT('%', #{dto.keyword}, '%') )
AND vector_status=#{dto.vectorStatus}
and category= #{dto.category}
ORDER BY created_at DESC
